# deny-policies.tf

# Create the deny policy definition
resource "azurerm_policy_definition" "deny_public_storage" {
  name         = "deny-public-storage-accounts"
  policy_type  = "Custom"
  mode         = "All"
  display_name = "Deny public blob access on storage accounts"
  management_group_id = var.corp_mg_id

  policy_rule = jsonencode({
    if = {
      allOf = [
        { field = "type", equals = "Microsoft.Storage/storageAccounts" },
        { field = "Microsoft.Storage/storageAccounts/allowBlobPublicAccess", equals = "true" }
      ]
    }
    then = {
      effect = "[parameters('effect')]"
    }
  })

  parameters = jsonencode({
    effect = {
      type         = "String"
      defaultValue = "deny"
      allowedValues = ["deny", "audit", "disabled"]
      metadata = { displayName = "Effect" }
    }
  })
}

# Assign with deny effect at MG scope
resource "azurerm_management_group_policy_assignment" "deny_public_storage" {
  name                 = "deny-public-storage"
  display_name         = "Deny public blob access on storage accounts"
  policy_definition_id = azurerm_policy_definition.deny_public_storage.id
  management_group_id  = var.corp_mg_id

  # Start with DoNotEnforce, switch to Default after validating
  enforce = true  # false = DoNotEnforce, true = Default (deny)

  parameters = jsonencode({
    effect = { value = "deny" }
  })

  non_compliance_message {
    content = "Storage accounts must not allow public blob access. Set allowBlobPublicAccess=false. See: https://wiki.contoso.com/azure-storage-guidelines"
  }

  not_scopes = [
    # Sandbox subscriptions excluded from deny — use audit only
    "/subscriptions/${var.sandbox_sub_id}"
  ]
}

# Assign same definition with audit effect on sandbox
resource "azurerm_subscription_policy_assignment" "audit_public_storage_sandbox" {
  name                 = "audit-public-storage"
  display_name         = "Audit public blob access (sandbox)"
  policy_definition_id = azurerm_policy_definition.deny_public_storage.id
  subscription_id      = "/subscriptions/${var.sandbox_sub_id}"
  enforce              = false
  parameters = jsonencode({
    effect = { value = "audit" }
  })
}

// storage.bicep — resource that must comply with deny policies at deploy time
param storageAccountName string
param location string = resourceGroup().location

// This will be DENIED if a deny policy targets allowBlobPublicAccess = true
// Correct: set allowBlobPublicAccess to false explicitly
resource storageAccount 'Microsoft.Storage/storageAccounts@2023-01-01' = {
  name: storageAccountName
  location: location
  sku: {
    name: 'Standard_LRS'
  }
  kind: 'StorageV2'
  properties: {
    allowBlobPublicAccess: false          // required: deny policy blocks true
    supportsHttpsTrafficOnly: true         // required: deny policy blocks false
    minimumTlsVersion: 'TLS1_2'           // required: deny policy blocks TLS1_0/TLS1_1
    allowSharedKeyAccess: false            // required if SharedKey deny policy exists
    networkAcls: {
      defaultAction: 'Deny'               // required if public network deny policy exists
      bypass: 'AzureServices'
    }
  }
}

output storageAccountId string = storageAccount.id
